import { NComponent, defineComponent, TabItemOption } from "@ncom/all";
import { genTabs } from "../data/tabsdata";

export default class Tabs6 extends NComponent {
  constructor() {
    super();
  }

  template() {
    return `
      <nc-tabs items={this.genTabs(5,null,true)} type='card' style='height:200px'></nc-tabs>
    `;
  }

  genTabs(count: number, activeIndex?: number, closable?: boolean): TabItemOption[] {
    return genTabs(count, activeIndex, closable);
  }
}

defineComponent("nc-tabs-ex6", Tabs6);
